const DEFAULT_PASSWORD_HASH = "27192d93602fb56a2f09cc815f5a38c219128e91b505a8e6ac837dea5b266564";
const DATA_KEY = "lentraVendorData_v1";
const SESSION_KEY = "lentraVendorSession_v1";
const PASS_KEY = "lentraVendorPasswordHash_v1";
let state = {
  data: [],
  category: "Semua",
  query: "",
  location: "Semua Lokasi",
  sortKey: "nama",
  sortDir: "asc",
  compact: false
};

const $ = (id) => document.getElementById(id);
const escapeHtml = (s) => String(s ?? "").replace(/[&<>"']/g, m => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]));
const normalize = (s) => String(s ?? "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

async function sha256(text) {
  const buffer = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(text));
  return [...new Uint8Array(buffer)].map(b => b.toString(16).padStart(2, "0")).join("");
}

function getPasswordHash() {
  return localStorage.getItem(PASS_KEY) || DEFAULT_PASSWORD_HASH;
}

function loadData() {
  try {
    const saved = JSON.parse(localStorage.getItem(DATA_KEY) || "null");
    state.data = Array.isArray(saved) && saved.length ? saved : DEFAULT_DATA;
  } catch(e) {
    state.data = DEFAULT_DATA;
  }
}

function saveData() {
  localStorage.setItem(DATA_KEY, JSON.stringify(state.data));
}

function isLoggedIn() {
  return sessionStorage.getItem(SESSION_KEY) === "1";
}

function showApp() {
  $("login").classList.add("hidden");
  $("app").classList.remove("hidden");
  loadData();
  renderAll();
}

function showLogin() {
  $("app").classList.add("hidden");
  $("login").classList.remove("hidden");
  renderLoginStats();
}

function getCategories() {
  return ["Semua", ...Array.from(new Set(state.data.map(x => x.kategori).filter(Boolean))).sort()];
}

function getLocations() {
  const locs = state.data.map(x => x.lokasi || "").filter(Boolean)
    .map(x => x.split(",")[0].trim()).filter(Boolean);
  return ["Semua Lokasi", ...Array.from(new Set(locs)).sort()];
}

function renderLoginStats() {
  const total = DEFAULT_DATA.length;
  const venue = DEFAULT_DATA.filter(x => /venue/i.test(x.kategori)).length;
  const cats = new Set(DEFAULT_DATA.map(x => x.kategori)).size;
  $("loginStats").innerHTML = `
    <div class="hero-stat"><b>${total}</b><span>Total data awal</span></div>
    <div class="hero-stat"><b>${venue}</b><span>Data venue</span></div>
    <div class="hero-stat"><b>${cats}</b><span>Kategori vendor</span></div>
  `;
}

function renderNav() {
  const cats = getCategories();
  const counts = Object.fromEntries(cats.map(c => [c, c === "Semua" ? state.data.length : state.data.filter(x => x.kategori === c).length]));
  $("categoryNav").innerHTML = cats.map(c => `
    <button class="nav-btn ${state.category === c ? "active" : ""}" data-cat="${escapeHtml(c)}">
      <span>${escapeHtml(c)}</span><small>${counts[c]}</small>
    </button>
  `).join("");
  $("categoryNav").querySelectorAll("button").forEach(btn => btn.addEventListener("click", () => {
    state.category = btn.dataset.cat;
    $("categoryFilter").value = state.category;
    renderAll();
  }));
}

function renderFilters() {
  const cats = getCategories();
  $("categoryFilter").innerHTML = cats.map(c => `<option>${escapeHtml(c)}</option>`).join("");
  $("categoryFilter").value = state.category;
  const locs = getLocations();
  $("locationFilter").innerHTML = locs.map(l => `<option>${escapeHtml(l)}</option>`).join("");
  $("locationFilter").value = state.location;
  $("kategoriList").innerHTML = cats.filter(c => c !== "Semua").map(c => `<option value="${escapeHtml(c)}"></option>`).join("");
}

function filteredData() {
  let rows = [...state.data];
  if (state.category !== "Semua") rows = rows.filter(x => x.kategori === state.category);
  if (state.location !== "Semua Lokasi") rows = rows.filter(x => (x.lokasi || "").startsWith(state.location));
  const q = normalize(state.query);
  if (q) {
    rows = rows.filter(x => normalize(Object.values(x).join(" ")).includes(q));
  }
  rows.sort((a,b) => {
    const av = normalize(a[state.sortKey] || "");
    const bv = normalize(b[state.sortKey] || "");
    if (av < bv) return state.sortDir === "asc" ? -1 : 1;
    if (av > bv) return state.sortDir === "asc" ? 1 : -1;
    return 0;
  });
  return rows;
}

function countWhere(fn) {
  return state.data.filter(fn).length;
}

function renderCards() {
  const cats = new Set(state.data.map(x => x.kategori));
  $("cards").innerHTML = `
    <div class="card"><div class="label">Total Database</div><div class="value">${state.data.length}</div><div class="mini">vendor/venue aktif dalam file</div></div>
    <div class="card"><div class="label">Venue</div><div class="value">${countWhere(x => /Venue/i.test(x.kategori))}</div><div class="mini">venue detail & directory</div></div>
    <div class="card"><div class="label">Vendor Produksi</div><div class="value">${countWhere(x => /Technical|Hybrid|Foto|Video|Printing/i.test(x.kategori))}</div><div class="mini">support event dan operasional</div></div>
    <div class="card"><div class="label">Kategori</div><div class="value">${cats.size}</div><div class="mini">klasifikasi database</div></div>
  `;
}

function contactLinks(text) {
  if (!text) return '<span class="muted">-</span>';
  const raw = escapeHtml(text);
  const phoneMatches = String(text).match(/(?:\+?62|0)[0-9\s\-()](7,)/g) || [];
  let output = raw;
  phoneMatches.forEach(p => {
    const clean = p.replace(/[^0-9+]/g, "").replace(/^0/, "62").replace(/^\+/, "");
    const safeP = escapeHtml(p);
    output = output.replace(safeP, `<a class="contact-link" href="https://wa.me/${clean}" target="_blank">${safeP}</a>`);
  });
  return output;
}

function emailLink(email) {
  if (!email) return '<span class="muted">-</span>';
  return `<a class="contact-link" href="mailto:${escapeHtml(email)}">${escapeHtml(email)}</a>`;
}

function shortText(text, max=120) {
  if (!text) return '<span class="muted">-</span>';
  const t = String(text);
  const cut = state.compact && t.length > max ? t.slice(0, max) + "..." : t;
  return escapeHtml(cut);
}

function renderTable() {
  const rows = filteredData();
  $("tableTitle").textContent = state.category === "Semua" ? "Semua vendor" : state.category;
  $("tableCount").textContent = `${rows.length} data ditampilkan dari ${state.data.length} total`;
  $("emptyState").classList.toggle("hidden", rows.length !== 0);
  $("tableBody").innerHTML = rows.map(r => `
    <tr>
      <td class="name-cell"><b>${escapeHtml(r.nama)}</b><span class="id-chip">${escapeHtml(r.id || "")} • ${escapeHtml(r.sumber || "Manual")}</span></td>
      <td><span class="chip">${escapeHtml(r.kategori || "-")}</span></td>
      <td>${shortText(r.jenis, 110)}</td>
      <td>${escapeHtml(r.lokasi || "-")}</td>
      <td>${contactLinks(r.kontak)}</td>
      <td>${emailLink(r.email)}</td>
      <td>${shortText(r.kapasitas, 120)}</td>
      <td>${shortText(r.rate, 140)}</td>
      <td>${shortText(r.catatan, 160)}</td>
      <td class="action-col nowrap">
        <button class="btn small secondary" data-view="${r.id}">Detail</button>
        <button class="btn small secondary" data-edit="${r.id}">Edit</button>
        <button class="btn small danger" data-del="${r.id}">Hapus</button>
      </td>
    </tr>
  `).join("");
  $("tableBody").querySelectorAll("[data-view]").forEach(b => b.addEventListener("click", () => openDetail(b.dataset.view)));
  $("tableBody").querySelectorAll("[data-edit]").forEach(b => b.addEventListener("click", () => openEdit(b.dataset.edit)));
  $("tableBody").querySelectorAll("[data-del]").forEach(b => b.addEventListener("click", () => deleteVendor(b.dataset.del)));
}

function renderAll() {
  renderNav();
  renderFilters();
  renderCards();
  renderTable();
}

function openModal(id) { $(id).classList.add("show"); }
function closeModal(id) { $(id).classList.remove("show"); }

function openAdd() {
  $("vendorModalTitle").textContent = "Tambah Vendor";
  $("vendorForm").reset();
  $("vendorId").value = "";
  openModal("vendorModal");
}

function openEdit(id) {
  const r = state.data.find(x => x.id === id);
  if (!r) return;
  $("vendorModalTitle").textContent = "Edit Vendor";
  $("vendorId").value = r.id;
  $("fNama").value = r.nama || "";
  $("fKategori").value = r.kategori || "";
  $("fJenis").value = r.jenis || "";
  $("fLokasi").value = r.lokasi || "";
  $("fKontak").value = r.kontak || "";
  $("fEmail").value = r.email || "";
  $("fKapasitas").value = r.kapasitas || "";
  $("fRate").value = r.rate || "";
  $("fCatatan").value = r.catatan || "";
  openModal("vendorModal");
}

function openDetail(id) {
  const r = state.data.find(x => x.id === id);
  if (!r) return;
  $("detailTitle").textContent = r.nama || "Detail Vendor";
  const fields = [
    ["ID", r.id], ["Kategori", r.kategori], ["Jenis / Spesialisasi", r.jenis], ["Lokasi", r.lokasi],
    ["Kontak", r.kontak], ["Email", r.email], ["Kapasitas", r.kapasitas], ["Rate / Estimasi", r.rate],
    ["Catatan / Remarks", r.catatan], ["Sumber", r.sumber]
  ];
  $("detailGrid").innerHTML = fields.map(([k,v]) => `<b>${escapeHtml(k)}</b><div>${k === "Kontak" ? contactLinks(v) : k === "Email" ? emailLink(v) : escapeHtml(v || "-")}</div>`).join("");
  openModal("detailModal");
}

function deleteVendor(id) {
  const r = state.data.find(x => x.id === id);
  if (!r) return;
  if (confirm(`Hapus data "${r.nama}"?`)) {
    state.data = state.data.filter(x => x.id !== id);
    saveData();
    renderAll();
    toast("Data dihapus.");
  }
}

function nextId() {
  const nums = state.data.map(x => parseInt(String(x.id || "").replace(/\D/g,""),10)).filter(Boolean);
  return "VD-" + String((Math.max(0, ...nums) + 1)).padStart(3, "0");
}

function exportCSV() {
  const rows = filteredData();
  const headers = ["id","kategori","nama","jenis","lokasi","kontak","email","kapasitas","rate","catatan","sumber"];
  const csv = [headers.join(",")].concat(rows.map(r => headers.map(h => {
    const cell = String(r[h] ?? "").replace(/"/g,'""');
    return `"${cell}"`;
  }).join(","))).join("\n");
  const blob = new Blob(["\ufeff" + csv], {type:"text/csv;charset=utf-8;"});
  const a = document.createElement("a");
  a.href = URL.createObjectURL(blob);
  a.download = "database_vendor_lentra_mice.csv";
  a.click();
  URL.revokeObjectURL(a.href);
  toast("CSV berhasil diekspor.");
}

function toast(msg) {
  const t = $("toast");
  t.textContent = msg;
  t.classList.add("show");
  setTimeout(() => t.classList.remove("show"), 2200);
}

document.addEventListener("click", (e) => {
  const close = e.target.getAttribute && e.target.getAttribute("data-close");
  if (close) closeModal(close);
});

$("loginForm").addEventListener("submit", async (e) => {
  e.preventDefault();
  $("loginError").textContent = "";
  const pass = $("password").value;
  const hash = await sha256(pass);
  if (hash === getPasswordHash()) {
    sessionStorage.setItem(SESSION_KEY, "1");
    $("password").value = "";
    showApp();
  } else {
    $("loginError").textContent = "Sandi salah. Periksa kembali sandi akses.";
  }
});

$("categoryFilter").addEventListener("change", e => { state.category = e.target.value; renderAll(); });
$("locationFilter").addEventListener("change", e => { state.location = e.target.value; renderAll(); });
$("searchInput").addEventListener("input", e => { state.query = e.target.value; renderTable(); });
$("btnClear").addEventListener("click", () => { state.query = ""; state.category = "Semua"; state.location = "Semua Lokasi"; $("searchInput").value = ""; renderAll(); });
$("btnExport").addEventListener("click", exportCSV);
$("btnPrint").addEventListener("click", () => window.print());
$("btnAdd").addEventListener("click", openAdd);
$("btnCompact").addEventListener("click", () => {
  state.compact = !state.compact;
  $("btnCompact").textContent = state.compact ? "Tampilan lengkap" : "Tampilan ringkas";
  renderTable();
});
$("btnLogout").addEventListener("click", () => { sessionStorage.removeItem(SESSION_KEY); showLogin(); });
$("btnTheme").addEventListener("click", () => document.body.classList.toggle("light"));
$("btnPassword").addEventListener("click", () => { $("passwordForm").reset(); openModal("passwordModal"); });
$("btnReset").addEventListener("click", () => {
  if (confirm("Reset database ke data awal dari PDF? Semua perubahan lokal akan hilang.")) {
    localStorage.removeItem(DATA_KEY);
    loadData();
    renderAll();
    toast("Database kembali ke data awal.");
  }
});

$("vendorForm").addEventListener("submit", (e) => {
  e.preventDefault();
  const id = $("vendorId").value || nextId();
  const item = {
    id,
    kategori: $("fKategori").value.trim(),
    nama: $("fNama").value.trim(),
    jenis: $("fJenis").value.trim(),
    lokasi: $("fLokasi").value.trim(),
    kontak: $("fKontak").value.trim(),
    email: $("fEmail").value.trim(),
    kapasitas: $("fKapasitas").value.trim(),
    rate: $("fRate").value.trim(),
    catatan: $("fCatatan").value.trim(),
    sumber: $("vendorId").value ? (state.data.find(x => x.id === id)?.sumber || "Manual") : "Manual"
  };
  const idx = state.data.findIndex(x => x.id === id);
  if (idx >= 0) state.data[idx] = item; else state.data.push(item);
  saveData();
  closeModal("vendorModal");
  renderAll();
  toast("Data berhasil disimpan.");
});

$("passwordForm").addEventListener("submit", async (e) => {
  e.preventDefault();
  const oldHash = await sha256($("oldPass").value);
  if (oldHash !== getPasswordHash()) return toast("Sandi lama tidak sesuai.");
  if ($("newPass").value !== $("newPass2").value) return toast("Konfirmasi sandi baru tidak sama.");
  localStorage.setItem(PASS_KEY, await sha256($("newPass").value));
  $("passwordForm").reset();
  closeModal("passwordModal");
  toast("Sandi berhasil diganti.");
});

document.querySelectorAll("th[data-sort]").forEach(th => {
  th.addEventListener("click", () => {
    const key = th.dataset.sort;
    if (state.sortKey === key) state.sortDir = state.sortDir === "asc" ? "desc" : "asc";
    else { state.sortKey = key; state.sortDir = "asc"; }
    renderTable();
  });
});

loadData();
renderLoginStats();
if (isLoggedIn()) showApp(); else showLogin();
